// ============================================================
//  WORLD  — static ground canvas + water ShaderMaterial
// ============================================================

const World = (() => {
  // ---- tile types ----
  const T = { GRASS: 0, DIRT: 1, WATER: 2, TREE: 3, STONE: 4, FLOWER: 5, PATH: 6 };

  const TILE_W = 16;
  const TILE_H = 16;

  const TRUNK_W = 28;
  const TRUNK_H = 32;
  const CANOPY_W = 50;
  const CANOPY_H = 50;
  let treeCanopies = [];  // { mesh, worldY } for depth sorting
  let treeColliders = []; // { x, y, hw, hh } — bottom-half trunk hitboxes in world coords
  let canopyMaterial = null;

  // ---- Stardew-inspired palettes: 5 shades dark→bright [R,G,B] ----
  const PAL = {
    [T.GRASS]:  [[40,90,18],[56,116,28],[76,148,44],[96,172,60],[120,200,76]],
    [T.DIRT]:   [[140,100,46],[164,126,64],[190,152,84],[212,174,104],[230,196,124]],
    [T.WATER]:  [[28,72,152],[40,96,178],[52,122,200],[70,150,224],[96,182,248]],
    [T.STONE]:  [[72,72,84],[92,94,110],[116,118,136],[140,142,162],[164,166,188]],
    [T.PATH]:   [[160,128,72],[184,152,92],[206,174,112],[226,196,134],[244,214,154]],
  };
  PAL[T.FLOWER] = PAL[T.GRASS];
  PAL[T.TREE]   = PAL[T.GRASS];

  function palIdx(n, type) {
    switch (type) {
      case T.GRASS: case T.FLOWER: case T.TREE:
        return n < 0.08 ? 0 : n < 0.24 ? 1 : n < 0.62 ? 2 : n < 0.84 ? 3 : 4;
      case T.DIRT:
        return n < 0.07 ? 0 : n < 0.22 ? 1 : n < 0.66 ? 2 : n < 0.86 ? 3 : 4;
      case T.WATER:
        return n < 0.14 ? 0 : n < 0.34 ? 1 : n < 0.64 ? 2 : n < 0.84 ? 3 : 4;
      case T.STONE:
        return n < 0.09 ? 0 : n < 0.28 ? 1 : n < 0.62 ? 2 : n < 0.82 ? 3 : 4;
      case T.PATH:
        return n < 0.06 ? 0 : n < 0.20 ? 1 : n < 0.58 ? 2 : n < 0.80 ? 3 : 4;
      default: return 2;
    }
  }

  function pxHash(a, b, c, d) {
    const x = Math.sin(a * 127.1 + b * 311.7 + c * 74.7 + (d || 0) * 531.3) * 43758.5453;
    return x - Math.floor(x);
  }

  function clampByte(v) { return v < 0 ? 0 : v > 255 ? 255 : v; }
  function lerp(a, b, t) { return a + (b - a) * t; }

  function hash(x, y) {
    const n = Math.sin(x * 127.1 + y * 311.7) * 43758.5453;
    return n - Math.floor(n);
  }

  function noise(x, y) {
    const ix = Math.floor(x), iy = Math.floor(y), fx = x - ix, fy = y - iy;
    const a  = hash(ix,     iy    ), b  = hash(ix + 1, iy    );
    const c2 = hash(ix,     iy + 1), d  = hash(ix + 1, iy + 1);
    const u  = fx * fx * (3 - 2 * fx), v = fy * fy * (3 - 2 * fy);
    return lerp(lerp(a, b, u), lerp(c2, d, u), v);
  }

  function smoothNoise(x, y, scale) {
    const sx = x * scale, sy = y * scale;
    const ix = Math.floor(sx), iy = Math.floor(sy);
    const fx = sx - ix, fy = sy - iy;
    const a = hash(ix, iy), b = hash(ix + 1, iy);
    const c2 = hash(ix, iy + 1), d2 = hash(ix + 1, iy + 1);
    const u = fx * fx * (3 - 2 * fx), v = fy * fy * (3 - 2 * fy);
    return lerp(lerp(a, b, u), lerp(c2, d2, u), v);
  }

  // ---- world generation ----
  let mapCols, mapRows, tileMap;

  function generate(cols, rows) {
    mapCols = cols; mapRows = rows; tileMap = [];
    for (let r = 0; r < rows; r++) {
      tileMap[r] = [];
      for (let c = 0; c < cols; c++) {
        let t = T.GRASS;
        if (r < 2 || r >= rows - 2 || c < 2 || c >= cols - 2) {
          t = T.WATER;
        } else {
          const n = noise(c * 0.16, r * 0.16);
          if      (n < 0.20) t = T.WATER;
          else if (n < 0.30) t = T.DIRT;
          else if (n < 0.46) t = T.STONE;
          else if (n < 0.72) t = T.GRASS;
          else if (n < 0.80) t = T.PATH;
          else               t = T.GRASS;   // was T.TREE — scatter trees separately
        }
        tileMap[r][c] = t;
      }
    }

    // Scatter individual trees on grass tiles (no clusters)
    // Use a seeded hash to get ~1 tree per 40 tiles, minimum 3 tiles apart
    const treeCandidates = [];
    for (let r = 3; r < rows - 3; r++) {
      for (let c = 3; c < cols - 3; c++) {
        if (tileMap[r][c] === T.GRASS || tileMap[r][c] === T.FLOWER) {
          // Pseudo-random per-tile: ~1 in 18 chance
          const h = Math.sin(c * 127.1 + r * 311.7) * 43758.5453;
          if ((h - Math.floor(h)) < 0.055) {
            treeCandidates.push({ c, r });
          }
        }
      }
    }
    // Enforce minimum spacing — reject trees too close to an already-placed tree
    const placed = [];
    const MIN_DIST = 3;
    for (const tc of treeCandidates) {
      let tooClose = false;
      for (const p of placed) {
        if (Math.abs(tc.c - p.c) < MIN_DIST && Math.abs(tc.r - p.r) < MIN_DIST) {
          tooClose = true; break;
        }
      }
      if (!tooClose) {
        tileMap[tc.r][tc.c] = T.TREE;
        placed.push(tc);
      }
    }
  }

  // ---- Three.js state ----
  let waterMaterial = null;
  const createdObjects = [];

  // ---- Water shader strings (WebGL 1 / GLSL ES 1.0) ----
  const WATER_VERT = `
    uniform vec2 uWorldSize;
    varying vec2 vUv;
    varying vec2 vWorldPos;
    void main() {
      vUv = uv;
      vWorldPos = uv * uWorldSize;
      gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
    }
  `;

  const WATER_FRAG = `
    uniform float uTime;
    uniform sampler2D uWaterTile;
    uniform sampler2D uMask;
    uniform vec2 uTileSize;
    uniform vec2 uWorldSize;
    uniform vec2 uMapSize;

    varying vec2 vUv;
    varying vec2 vWorldPos;

    float hash21(vec2 p) {
      float h = dot(p, vec2(127.1, 311.7));
      return fract(sin(h) * 43758.5453);
    }

    void main() {
      // Mask: discard non-water pixels
      vec2 tileUv = vec2(vUv.x, 1.0 - vUv.y);
      float mask = texture2D(uMask, tileUv).r;
      if (mask < 0.5) discard;

      // Pixel-art quantization: snap to whole world pixels
      vec2 wp = floor(vWorldPos);

      // Gentle UV wobble — shifts sampling coords with slow waves
      float wobbleX = sin(wp.y * 0.12 + uTime * 0.7) * 1.5;
      float wobbleY = sin(wp.x * 0.10 + uTime * 0.5) * 1.5;
      vec2 wobbled = wp + vec2(wobbleX, wobbleY);
      wobbled = floor(wobbled); // re-snap after wobble

      // Slow diagonal drift so the water "flows"
      float t = uTime * 0.35;
      vec2 drift = vec2(t * 3.0, t * 2.0);

      // Sample Water2.png tile with wobble + drift
      vec2 tileCoord = mod(wobbled * 4.0 + drift, uTileSize) / uTileSize;
      vec3 color = texture2D(uWaterTile, tileCoord).rgb;

      // Slow global color shift (very subtle hue breathing)
      float shift = sin(uTime * 0.25) * 0.025;
      color.g += shift * 0.5;
      color.b += shift;

      gl_FragColor = vec4(clamp(color, 0.0, 1.0), 1.0);
    }
  `;

  // ---- Tree canopy shader (wind sway + translucency) ----
  const CANOPY_VERT = `
    uniform float uTime;
    varying vec2 vUv;
    void main() {
      vUv = uv;
      vec3 pos = position;
      // Wind sway: top of canopy sways more than bottom
      float swayAmount = uv.y * 0.8;
      pos.x += sin(uTime * 1.5 + position.y * 0.3) * swayAmount;
      gl_Position = projectionMatrix * modelViewMatrix * vec4(pos, 1.0);
    }
  `;

  const CANOPY_FRAG = `
    uniform sampler2D uCanopyTex;
    uniform float uTime;
    uniform float uAlpha;

    varying vec2 vUv;

    void main() {
      vec4 texColor = texture2D(uCanopyTex, vUv);
      if (texColor.a < 0.1) discard;

      // Subtle leaf shimmer
      float shimmer = sin(vUv.x * 30.0 + vUv.y * 20.0 + uTime * 2.0) * 0.04;
      texColor.rgb += shimmer;

      texColor.a *= uAlpha;
      gl_FragColor = texColor;
    }
  `;

  function disposeAll() {
    createdObjects.forEach(obj => {
      if (obj.geometry) obj.geometry.dispose();
      if (obj.material) {
        // dispose uniforms textures
        if (obj.material.uniforms) {
          Object.values(obj.material.uniforms).forEach(u => {
            if (u.value && u.value.isTexture) u.value.dispose();
          });
        }
        if (obj.material.map) obj.material.map.dispose();
        obj.material.dispose();
      }
    });
    createdObjects.length = 0;
    waterMaterial = null;
    canopyMaterial = null;
    treeCanopies = [];
  }

  // ---- scene building ----
  function buildScene(scene) {
    disposeAll();

    const worldW = mapCols * TILE_W;
    const worldH = mapRows * TILE_H;

    const treePos = [];
    for (let r = 0; r < mapRows; r++)
      for (let c = 0; c < mapCols; c++)
        if (tileMap[r][c] === T.TREE) treePos.push({ c, r });

    // ---- Static ground canvas (painted once, never updated) ----
    const groundCanvas = document.createElement('canvas');
    groundCanvas.width  = worldW;
    groundCanvas.height = worldH;
    const gCtx = groundCanvas.getContext('2d');
    _paintBaseLayer(gCtx);
    _paintTransitions(gCtx);

    const groundTex = new THREE.CanvasTexture(groundCanvas);
    groundTex.magFilter = THREE.NearestFilter;
    groundTex.minFilter = THREE.NearestFilter;

    const groundMesh = new THREE.Mesh(
      new THREE.PlaneGeometry(worldW, worldH),
      new THREE.MeshBasicMaterial({ map: groundTex, depthWrite: false })
    );
    groundMesh.position.set(worldW / 2, -worldH / 2, 0);
    groundMesh.renderOrder = 0;
    scene.add(groundMesh);
    createdObjects.push(groundMesh);

    // ---- Animated water overlay (ShaderMaterial) ----
    const rgbaData = new Uint8Array(_waterTileW * _waterTileH * 4);
    for (let i = 0, j = 0; i < _waterTile.length; i += 3, j += 4) {
      rgbaData[j]     = _waterTile[i];
      rgbaData[j + 1] = _waterTile[i + 1];
      rgbaData[j + 2] = _waterTile[i + 2];
      rgbaData[j + 3] = 255;
    }
    const waterBaseTex = new THREE.DataTexture(
      rgbaData, _waterTileW, _waterTileH,
      THREE.RGBAFormat, THREE.UnsignedByteType
    );
    waterBaseTex.magFilter = THREE.NearestFilter;
    waterBaseTex.minFilter = THREE.NearestFilter;
    waterBaseTex.wrapS = THREE.RepeatWrapping;
    waterBaseTex.wrapT = THREE.RepeatWrapping;
    waterBaseTex.needsUpdate = true;

    // Water mask (1 texel per tile: white=water, black=land)
    const maskData = new Uint8Array(mapCols * mapRows * 4);
    for (let r = 0; r < mapRows; r++) {
      for (let c = 0; c < mapCols; c++) {
        const idx = (r * mapCols + c) * 4;
        const v = tileMap[r][c] === T.WATER ? 255 : 0;
        maskData[idx] = v; maskData[idx+1] = v;
        maskData[idx+2] = v; maskData[idx+3] = v;
      }
    }
    const waterMaskTex = new THREE.DataTexture(
      maskData, mapCols, mapRows,
      THREE.RGBAFormat, THREE.UnsignedByteType
    );
    waterMaskTex.magFilter = THREE.NearestFilter;
    waterMaskTex.minFilter = THREE.NearestFilter;
    waterMaskTex.needsUpdate = true;

    waterMaterial = new THREE.ShaderMaterial({
      uniforms: {
        uTime:      { value: 0.0 },
        uWaterTile: { value: waterBaseTex },
        uMask:      { value: waterMaskTex },
        uTileSize:  { value: new THREE.Vector2(_waterTileW, _waterTileH) },
        uWorldSize: { value: new THREE.Vector2(worldW, worldH) },
        uMapSize:   { value: new THREE.Vector2(mapCols, mapRows) },
      },
      vertexShader:   WATER_VERT,
      fragmentShader: WATER_FRAG,
      transparent: true,
      depthWrite: false,
    });

    const waterMesh = new THREE.Mesh(
      new THREE.PlaneGeometry(worldW, worldH),
      waterMaterial
    );
    waterMesh.position.set(worldW / 2, -worldH / 2, 0);
    waterMesh.renderOrder = 0.5;
    scene.add(waterMesh);
    createdObjects.push(waterMesh);

    // ---- Trees (trunk + canopy with depth sorting) ----
    _buildTrees(scene, treePos);
  }

  // ---- Embedded grass tiles (RGB, base64) ----
  // Green.png: plain grass (76x68)
  const _greenTileW = 76, _greenTileH = 68;
  const _greenTileB64 = '';
  const _greenTile = (() => {
    const bin = atob(_greenTileB64);
    const arr = new Uint8Array(bin.length);
    for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);
    return arr;
  })();

  // Flower.png: grass with flowers (76x78)
  const _flowerTileW = 76, _flowerTileH = 78;
  const _flowerTileB64 = '';
  const _flowerTile = (() => {
    const bin = atob(_flowerTileB64);
    const arr = new Uint8Array(bin.length);
    for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);
    return arr;
  })();

  // Grassflower.png: grass with scattered flowers (76x78)
  const _grassflowerTileW = 76, _grassflowerTileH = 78;
  const _grassflowerTileB64 = '';
  const _grassflowerTile = (() => {
    const bin = atob(_grassflowerTileB64);
    const arr = new Uint8Array(bin.length);
    for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);
    return arr;
  })();

  // Rock.png: rocky path (76x68)
  const _rockTileW = 76, _rockTileH = 68;
  const _rockTileB64 = '';
  const _rockTile = (() => {
    const bin = atob(_rockTileB64);
    const arr = new Uint8Array(bin.length);
    for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);
    return arr;
  })();

  // ---- Embedded 286x248 water tile (RGB, base64) ----
  const _waterTileW = 286, _waterTileH = 248;
  const _waterTileB64 = '';
  const _waterTile = (() => {
    const bin = atob(_waterTileB64);
    const arr = new Uint8Array(bin.length);
    for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);
    return arr;
  })();

  // ---- Pass 1: Base pixel layer ----
  function _paintBaseLayer(ctx) {
    const worldW = mapCols * TILE_W;
    const imgData = ctx.createImageData(worldW, mapRows * TILE_H);
    const d = imgData.data;

    for (let r = 0; r < mapRows; r++) {
      for (let c = 0; c < mapCols; c++) {
        const type = tileMap[r][c];

        const drawType = type === T.TREE ? T.GRASS : type;
        const pal = PAL[drawType] || PAL[T.GRASS];

        for (let py = 0; py < TILE_H; py++) {
          for (let px = 0; px < TILE_W; px++) {
            const wx = c * TILE_W + px;
            const wy = r * TILE_H + py;
            const i  = (wy * worldW + wx) * 4;

            let rv, gv, bv;

            if (type === T.WATER) {
              const tx = (wx * 4) % _waterTileW;
              const ty = (wy * 4) % _waterTileH;
              const ti = (ty * _waterTileW + tx) * 3;
              rv = _waterTile[ti];
              gv = _waterTile[ti + 1];
              bv = _waterTile[ti + 2];
            } else if (drawType === T.GRASS || drawType === T.FLOWER) {
              // Pick 1 of 3 grass variants per tile (deterministic by tile coords)
              const tileVariant = (c * 7 + r * 13) % 3;
              let tile, tw, th;
              if (tileVariant === 0)      { tile = _greenTile;       tw = _greenTileW;       th = _greenTileH; }
              else if (tileVariant === 1) { tile = _flowerTile;      tw = _flowerTileW;      th = _flowerTileH; }
              else                        { tile = _grassflowerTile; tw = _grassflowerTileW; th = _grassflowerTileH; }
              // Map px,py (0..15) across full tile image
              const tx = Math.floor(px * tw / TILE_W);
              const ty = Math.floor(py * th / TILE_H);
              const ti = (ty * tw + tx) * 3;
              rv = tile[ti]; gv = tile[ti + 1]; bv = tile[ti + 2];

              // Edge blend: average with neighbor tile's color at tile borders (2px band)
              const edgeX = px < 2 ? -1 : px >= TILE_W - 2 ? 1 : 0;
              const edgeY = py < 2 ? -1 : py >= TILE_H - 2 ? 1 : 0;
              if (edgeX !== 0 || edgeY !== 0) {
                const nc = c + edgeX, nr = r + edgeY;
                if (nc >= 0 && nc < mapCols && nr >= 0 && nr < mapRows) {
                  const nt = tileMap[nr][nc];
                  if (nt === T.GRASS || nt === T.FLOWER || nt === T.TREE) {
                    const nv = (nc * 7 + nr * 13) % 3;
                    let nt2, nw, nh;
                    if (nv === 0)      { nt2 = _greenTile;       nw = _greenTileW;       nh = _greenTileH; }
                    else if (nv === 1) { nt2 = _flowerTile;      nw = _flowerTileW;      nh = _flowerTileH; }
                    else               { nt2 = _grassflowerTile; nw = _grassflowerTileW; nh = _grassflowerTileH; }
                    const ntx = Math.floor(px * nw / TILE_W);
                    const nty = Math.floor(py * nh / TILE_H);
                    const nti = (nty * nw + ntx) * 3;
                    rv = (rv + nt2[nti]) >> 1;
                    gv = (gv + nt2[nti + 1]) >> 1;
                    bv = (bv + nt2[nti + 2]) >> 1;
                  }
                }
              }
            } else if (drawType === T.STONE) {
              // Rocky path tile — fit full image into one game tile
              const tx = Math.floor(px * _rockTileW / TILE_W);
              const ty = Math.floor(py * _rockTileH / TILE_H);
              const ti = (ty * _rockTileW + tx) * 3;
              rv = _rockTile[ti]; gv = _rockTile[ti + 1]; bv = _rockTile[ti + 2];

              // Edge blend with adjacent grass
              const edgeX = px < 2 ? -1 : px >= TILE_W - 2 ? 1 : 0;
              const edgeY = py < 2 ? -1 : py >= TILE_H - 2 ? 1 : 0;
              if (edgeX !== 0 || edgeY !== 0) {
                const nc = c + edgeX, nr = r + edgeY;
                if (nc >= 0 && nc < mapCols && nr >= 0 && nr < mapRows) {
                  const nt = tileMap[nr][nc];
                  if (nt === T.GRASS || nt === T.FLOWER || nt === T.TREE) {
                    const nv = (nc * 7 + nr * 13) % 3;
                    let nt2, nw, nh;
                    if (nv === 0)      { nt2 = _greenTile;       nw = _greenTileW;       nh = _greenTileH; }
                    else if (nv === 1) { nt2 = _flowerTile;      nw = _flowerTileW;      nh = _flowerTileH; }
                    else               { nt2 = _grassflowerTile; nw = _grassflowerTileW; nh = _grassflowerTileH; }
                    const ntx = Math.floor(px * nw / TILE_W);
                    const nty = Math.floor(py * nh / TILE_H);
                    const nti = (nty * nw + ntx) * 3;
                    rv = (rv + nt2[nti]) >> 1;
                    gv = (gv + nt2[nti + 1]) >> 1;
                    bv = (bv + nt2[nti + 2]) >> 1;
                  }
                }
              }
            } else {
              const ns = smoothNoise(c + px / TILE_W, r + py / TILE_H, 0.35);
              const nf = pxHash(px, py, c * 17 + r * 31, drawType);
              const n  = ns * 0.6 + nf * 0.4;
              const ci = palIdx(n, drawType);
              [rv, gv, bv] = pal[ci];
              const jitter = Math.round((pxHash(px + 7, py + 3, c, r) - 0.5) * 8);
              rv += jitter; gv += jitter; bv += jitter;
            }

            d[i]   = clampByte(rv);
            d[i+1] = clampByte(gv);
            d[i+2] = clampByte(bv);
            d[i+3] = 255;
          }
        }
      }
    }

    ctx.putImageData(imgData, 0, 0);
  }

  // ---- Pass 2: Terrain transitions ----
  function _paintTransitions(ctx) {
    const grassPal  = PAL[T.GRASS];
    const midGrass  = `rgb(${grassPal[2][0]},${grassPal[2][1]},${grassPal[2][2]})`;
    const darkGrass = `rgb(${grassPal[1][0]},${grassPal[1][1]},${grassPal[1][2]})`;

    for (let r = 0; r < mapRows; r++) {
      for (let c = 0; c < mapCols; c++) {
        const type = tileMap[r][c];
        if (type === T.WATER || type === T.GRASS || type === T.FLOWER || type === T.TREE) continue;

        const above = r > 0         ? tileMap[r - 1][c] : null;
        const left  = c > 0         ? tileMap[r][c - 1] : null;
        const below = r < mapRows-1 ? tileMap[r + 1][c] : null;
        const right = c < mapCols-1 ? tileMap[r][c + 1] : null;

        const isGrassy = t => t === T.GRASS || t === T.FLOWER || t === T.TREE;

        const tx = c * TILE_W, ty = r * TILE_H;

        if (isGrassy(above)) {
          ctx.fillStyle = midGrass;
          for (let px = 1; px < TILE_W - 1; px++)
            if (pxHash(px, r, c, 1) > 0.38) ctx.fillRect(tx + px, ty, 1, 1);
          ctx.fillStyle = darkGrass;
          for (let px = 1; px < TILE_W - 1; px++)
            if (pxHash(px, r, c, 2) > 0.55) ctx.fillRect(tx + px, ty + 1, 1, 1);
        }

        if (isGrassy(left)) {
          ctx.fillStyle = midGrass;
          for (let py = 1; py < TILE_H - 1; py++)
            if (pxHash(c, py, r, 3) > 0.38) ctx.fillRect(tx, ty + py, 1, 1);
          ctx.fillStyle = darkGrass;
          for (let py = 1; py < TILE_H - 1; py++)
            if (pxHash(c, py, r, 4) > 0.55) ctx.fillRect(tx + 1, ty + py, 1, 1);
        }

        if (isGrassy(below)) {
          ctx.fillStyle = 'rgba(0,0,0,0.18)';
          ctx.fillRect(tx, ty + TILE_H - 2, TILE_W, 2);
        }
        if (isGrassy(right)) {
          ctx.fillStyle = 'rgba(0,0,0,0.18)';
          ctx.fillRect(tx + TILE_W - 2, ty, 2, TILE_H);
        }

        // Shadow on land edges adjacent to water (water shader sits on top)
        if (below === T.WATER) {
          ctx.fillStyle = 'rgba(0,20,60,0.20)';
          ctx.fillRect(tx, ty + TILE_H - 2, TILE_W, 2);
        }
        if (right === T.WATER) {
          ctx.fillStyle = 'rgba(0,20,60,0.20)';
          ctx.fillRect(tx + TILE_W - 2, ty, 2, TILE_H);
        }
      }
    }
  }

  function updateWater(time) {
    if (waterMaterial) waterMaterial.uniforms.uTime.value = time;
  }

  // ---- Tree building ----
  function _buildTrees(scene, tiles) {
    if (!tiles.length) return;
    treeCanopies = [];
    treeColliders = [];

    // ---- Trunk texture ----
    const trunkCv = document.createElement('canvas');
    trunkCv.width = TRUNK_W; trunkCv.height = TRUNK_H;
    const trunkCtx = trunkCv.getContext('2d');
    _drawTrunk(trunkCtx);
    const trunkTex = new THREE.CanvasTexture(trunkCv);
    trunkTex.magFilter = THREE.NearestFilter;
    trunkTex.minFilter = THREE.NearestFilter;

    // ---- Canopy texture ----
    const canopyCv = document.createElement('canvas');
    canopyCv.width = CANOPY_W; canopyCv.height = CANOPY_H;
    const canopyCtx = canopyCv.getContext('2d');
    _drawCanopy(canopyCtx);
    const canopyTex = new THREE.CanvasTexture(canopyCv);
    canopyTex.magFilter = THREE.NearestFilter;
    canopyTex.minFilter = THREE.NearestFilter;

    const trunkGeo = new THREE.PlaneGeometry(TRUNK_W, TRUNK_H);
    const canopyGeo = new THREE.PlaneGeometry(CANOPY_W, CANOPY_H);

    tiles.forEach(({ c, r }) => {
      const worldY = r * TILE_H + TILE_H / 2;
      const treeX = c * TILE_W + TILE_W / 2;

      // Trunk mesh — depthWrite off so renderOrder controls draw order
      const tMat = new THREE.MeshBasicMaterial({
        map: trunkTex, transparent: true, alphaTest: 0.05, opacity: 1.0,
        depthWrite: false,
      });
      const tMesh = new THREE.Mesh(trunkGeo, tMat);
      const trunkY = -worldY + 2 - TRUNK_H / 2 + 10;
      tMesh.position.set(treeX, trunkY, 0.003);
      tMesh.renderOrder = 1;
      scene.add(tMesh);
      createdObjects.push(tMesh);

      // Canopy mesh — depthWrite off, renderOrder controls draw order
      const cMat = new THREE.ShaderMaterial({
        uniforms: {
          uCanopyTex: { value: canopyTex },
          uTime:      { value: 0.0 },
          uAlpha:     { value: 1.0 },
        },
        vertexShader:   CANOPY_VERT,
        fragmentShader: CANOPY_FRAG,
        transparent: true,
        depthWrite: false,
      });
      const cMesh = new THREE.Mesh(canopyGeo, cMat);
      cMesh.position.set(treeX, -worldY + CANOPY_H / 2 + 2, 0.004);
      cMesh.renderOrder = 1;
      scene.add(cMesh);
      createdObjects.push(cMesh);

      // Trunk collision
      const trunkCenterY = worldY + 2;
      const colliderCenterY = trunkCenterY + TRUNK_H * 0.25;
      const colliderHH = TRUNK_H * 0.25;

      treeCanopies.push({
        canopy: cMesh, trunk: tMesh,
        worldY, col: c, targetAlpha: 1.0, currentAlpha: 1.0,
      });
      treeColliders.push({
        x: treeX,
        y: colliderCenterY,
        hw: TRUNK_W * 0.5,
        hh: colliderHH,
      });
    });
  }

  function updateTrees(playerY, playerX, gameTime) {
    const FADE_SPEED = 3.0; // per second — smooth fade
    const dt = 0.016; // approximate frame dt

    for (let i = 0; i < treeCanopies.length; i++) {
      const tc = treeCanopies[i];
      const cMat = tc.canopy.material;
      cMat.uniforms.uTime.value = gameTime;

      // Use player's feet Y for depth comparison (player center + half height)
      const playerFeetY = playerY + 12; // SIZE_H/2 ≈ 12
      const treeX = tc.col * TILE_W + TILE_W / 2;
      const dx = Math.abs(playerX - treeX);

      // Default: player in front (renderOrder 2 > 1). Only put tree in front
      // when player's feet are above the tree tile center (walking behind it)
      if (playerFeetY < tc.worldY) {
        // Player above tree → tree in front, fade if overlapping
        tc.canopy.renderOrder = 3;
        tc.trunk.renderOrder = 3;
        const dy = tc.worldY - playerFeetY;
        if (dx < CANOPY_W * 0.6 && dy < CANOPY_H * 0.7) {
          tc.targetAlpha = 0.35;
        } else {
          tc.targetAlpha = 1.0;
        }
      } else {
        // Player's feet below tree base → tree renders behind player
        tc.canopy.renderOrder = 1;
        tc.trunk.renderOrder = 1;
        tc.targetAlpha = 1.0;
      }

      // Smooth lerp toward target
      if (tc.currentAlpha < tc.targetAlpha) {
        tc.currentAlpha = Math.min(tc.targetAlpha, tc.currentAlpha + FADE_SPEED * dt);
      } else if (tc.currentAlpha > tc.targetAlpha) {
        tc.currentAlpha = Math.max(tc.targetAlpha, tc.currentAlpha - FADE_SPEED * dt);
      }

      // Apply to both canopy and trunk
      cMat.uniforms.uAlpha.value = tc.currentAlpha;
      tc.trunk.material.opacity = tc.currentAlpha;
    }
  }

  // Check if a point+hitbox overlaps any tree trunk collider (bottom half)
  function isTreeBlocked(px, py, hw, hh) {
    for (let i = 0; i < treeColliders.length; i++) {
      const tc = treeColliders[i];
      if (Math.abs(px - tc.x) < hw + tc.hw && Math.abs(py - tc.y) < hh + tc.hh) {
        return true;
      }
    }
    return false;
  }

  function _drawTrunk(ctx) {
    const w = TRUNK_W, h = TRUNK_H;
    ctx.clearRect(0, 0, w, h);

    const imgData = ctx.createImageData(w, h);
    const d = imgData.data;
    const cx = w / 2;

    // Bark colour palette: dark shadow → highlight
    const bark = [
      [42, 24, 10],   // deep shadow
      [56, 34, 16],   // dark bark
      [72, 46, 22],   // mid bark
      [88, 58, 30],   // light bark
      [105, 72, 38],  // highlight
      [62, 40, 18],   // knot colour
    ];

    for (let py = 0; py < h; py++) {
      // Trunk width — tapers up, widens into root flare at bottom
      const topW = 4;
      const midW = 5;
      const rootW = 8;
      const t = py / h;
      let halfW;
      if (t < 0.7) {
        halfW = topW + (midW - topW) * (t / 0.7);
      } else {
        halfW = midW + (rootW - midW) * ((t - 0.7) / 0.3);
      }

      for (let px = 0; px < w; px++) {
        const dx = px - cx;
        if (Math.abs(dx) > halfW) continue;

        // Horizontal shading: light on left, dark on right
        const lr = (dx + halfW) / (halfW * 2); // 0=left, 1=right
        // Vertical bark line noise
        const barkNoise = pxHash(px, py, 3, 7) * 0.4;
        const shade = (1 - lr) * 0.5 + barkNoise + 0.1;

        let si = Math.floor(shade * 4);
        si = Math.max(0, Math.min(4, si));

        // Knots: scattered dark spots
        const knotChance = pxHash(px, py, 13, 17);
        if (knotChance > 0.92 && Math.abs(dx) < halfW - 1) si = 5;

        const col = bark[si];
        const jitter = Math.round((pxHash(px + 5, py + 3, 9, 11) - 0.5) * 8);
        const idx = (py * w + px) * 4;
        d[idx]   = clampByte(col[0] + jitter);
        d[idx+1] = clampByte(col[1] + jitter);
        d[idx+2] = clampByte(col[2] + jitter);
        d[idx+3] = 255;
      }

      // Branch stubs on left/right side of trunk at certain heights
      if (py === 4 || py === 5) {
        // Left branch stub
        for (let bx = 0; bx < 3; bx++) {
          const bpx = Math.floor(cx - halfW - bx - 1);
          if (bpx < 0) continue;
          const idx = (py * w + bpx) * 4;
          const col = bark[py === 4 ? 3 : 2];
          d[idx] = col[0]; d[idx+1] = col[1]; d[idx+2] = col[2]; d[idx+3] = 255;
        }
      }
      if (py === 10 || py === 11) {
        // Right branch stub
        for (let bx = 0; bx < 3; bx++) {
          const bpx = Math.floor(cx + halfW + bx + 1);
          if (bpx >= w) continue;
          const idx = (py * w + bpx) * 4;
          const col = bark[py === 10 ? 3 : 2];
          d[idx] = col[0]; d[idx+1] = col[1]; d[idx+2] = col[2]; d[idx+3] = 255;
        }
      }
    }

    // Root tendrils at very bottom
    const rootY = h - 2;
    for (let ry = rootY; ry < h; ry++) {
      for (let rx = -9; rx <= 9; rx++) {
        const rpx = Math.floor(cx + rx);
        if (rpx < 0 || rpx >= w) continue;
        if (pxHash(rpx, ry, 5, 3) > 0.55) continue;
        const idx = (ry * w + rpx) * 4;
        if (d[idx + 3] > 0) continue; // already drawn
        const col = bark[1];
        d[idx] = col[0]; d[idx+1] = col[1]; d[idx+2] = col[2]; d[idx+3] = 255;
      }
    }

    ctx.putImageData(imgData, 0, 0);
  }

  function _drawCanopy(ctx) {
    const w = CANOPY_W, h = CANOPY_H;
    ctx.clearRect(0, 0, w, h);

    const imgData = ctx.createImageData(w, h);
    const d = imgData.data;

    // Leaf colour palette: deep shadow → bright highlight
    const shades = [
      [16, 38, 12],    // deepest shadow
      [24, 56, 20],    // dark green
      [34, 78, 28],    // shadow green
      [48, 105, 36],   // mid dark
      [62, 130, 44],   // mid green
      [78, 155, 54],   // bright green
      [96, 178, 66],   // light green
      [118, 198, 82],  // highlight
    ];

    // Multiple overlapping leaf clusters to create organic shape
    const clusters = [
      { x: w * 0.5,  y: h * 0.32, rx: w * 0.44, ry: h * 0.30 },  // main top mass
      { x: w * 0.32, y: h * 0.48, rx: w * 0.30, ry: h * 0.28 },  // left lobe
      { x: w * 0.68, y: h * 0.46, rx: w * 0.30, ry: h * 0.26 },  // right lobe
      { x: w * 0.44, y: h * 0.60, rx: w * 0.26, ry: h * 0.22 },  // lower left
      { x: w * 0.58, y: h * 0.62, rx: w * 0.24, ry: h * 0.20 },  // lower right
      { x: w * 0.50, y: h * 0.22, rx: w * 0.28, ry: h * 0.20 },  // crown top
      { x: w * 0.38, y: h * 0.36, rx: w * 0.22, ry: h * 0.18 },  // upper left detail
      { x: w * 0.62, y: h * 0.34, rx: w * 0.20, ry: h * 0.16 },  // upper right detail
    ];

    for (let py = 0; py < h; py++) {
      for (let px = 0; px < w; px++) {
        // Check if pixel is inside any leaf cluster
        let minDist = 999;
        let insideAny = false;

        for (let ci = 0; ci < clusters.length; ci++) {
          const cl = clusters[ci];
          const dx = (px - cl.x) / cl.rx;
          const dy = (py - cl.y) / cl.ry;
          const dist = dx * dx + dy * dy;

          // Jagged edge per cluster
          const edgeNoise = (pxHash(px + ci * 7, py + ci * 13, 7 + ci, 3) - 0.5) * 0.35;
          if (dist < 1.0 + edgeNoise) {
            insideAny = true;
            if (dist < minDist) minDist = dist;
          }
        }

        if (!insideAny) continue;

        // --- Leaf detail shading ---
        // Light from upper-left
        const globalLx = (px / w - 0.3);
        const globalLy = (py / h - 0.2);
        const lightFrac = 1.0 - (globalLx * 0.4 + globalLy * 0.6);

        // Per-pixel leaf clump noise (creates leafy texture)
        const leafNoise1 = pxHash(px, py, 11, 5) * 0.35;
        const leafNoise2 = pxHash(Math.floor(px / 2), Math.floor(py / 2), 3, 9) * 0.25;

        // Depth — inner pixels brighter, edge pixels darker
        const depthFrac = (1 - minDist) * 0.3;

        // Combine into shade index
        const shade = lightFrac * 0.45 + leafNoise1 + leafNoise2 + depthFrac;
        let si = Math.floor(shade * 7);
        si = Math.max(0, Math.min(7, si));

        // Occasional dark gap pixels (negative space between leaves)
        const gapChance = pxHash(px, py, 19, 23);
        if (gapChance > 0.94 && minDist > 0.5) {
          si = Math.max(0, si - 3);
        }

        const col = shades[si];
        const jitter = Math.round((pxHash(px + 3, py + 7, 5, 9) - 0.5) * 8);
        const idx = (py * w + px) * 4;
        d[idx]   = clampByte(col[0] + jitter);
        d[idx+1] = clampByte(col[1] + jitter);
        d[idx+2] = clampByte(col[2] + jitter);
        d[idx+3] = 255;
      }
    }
    ctx.putImageData(imgData, 0, 0);
  }

  // ---- public API ----
  return {
    T,
    TILE_W,
    TILE_H,
    generate,
    buildScene,
    disposeAll,
    updateWater,
    updateTrees,
    isTreeBlocked,
    tileAt: (col, row) => tileMap[row]?.[col],
    cols:   () => mapCols,
    rows:   () => mapRows,
  };
})();
